package json_parser

import (
	"bytes"
	"fmt"
	"io"
	"sync"

	jsoniter "github.com/json-iterator/go"
	"golang.org/x/sys/unix"
)

// getOptimalBlockSize returns the filesystem's block size or a default value
func getOptimalBlockSize() uint32 {
	var statfs unix.Statfs_t
	if err := unix.Statfs("/", &statfs); err != nil {
		// fallback to 4KB if can't determine block size
		return 4 * 1024
	}

	return statfs.Bsize
}

var (
	json      = jsoniter.ConfigFastest
	chunkSize = getOptimalBlockSize()

	mapPool = sync.Pool{
		New: func() interface{} {
			return make(map[string]interface{}, 16) // Pre-allocate for typical JSON objects
		},
	}

	bufferPool = sync.Pool{
		New: func() interface{} {
			return bytes.NewBuffer(make([]byte, 0, chunkSize))
		},
	}
)

// UnmarshalJSONBuffer processes a JSON stream from a *bytes.Reader and deserializes it into a slice of maps.
// It efficiently handles:
// - Single JSON objects: {"key": "value"}
// - JSON arrays: [{"key": "value"}, {"key2": "value2"}]
// - Multiple concatenated JSON objects: {"key1": "value1"}{"key2": "value2"}
// - Multiple concatenated JSON arrays: [{"key1": "value1"}][{"key2": "value2"}]
// - Mixed JSON objects and arrays: {"key1": "value1"}[{"key2": "value2"}]{"key3": "value3"}
//
// The function processes the input in chunks to maintain memory efficiency and uses object pooling
// to reduce GC pressure. It skips invalid JSON and continues processing.
//
// Memory Usage:
// - Uses a 32KB buffer for reading
// - Pools map objects to reduce allocations
// - Processes data in streaming fashion without loading entire input
//
// Returns:
// - []map[string]interface{}: Slice of successfully parsed JSON objects
// - error: If no valid JSON objects were found or if there was an error reading input
func UnmarshalJSONBuffer(reader io.Reader) ([]map[string]interface{}, error) {
	// Pre-allocate results slice for typical bulk request size
	results := make([]map[string]interface{}, 0, 8)

	// Get a buffer from the pool and ensure it's clean
	buffer := bufferPool.Get().(*bytes.Buffer)
	buffer.Reset()
	defer bufferPool.Put(buffer) // Return buffer to pool when done

	chunk := make([]byte, chunkSize)

	// Reads input in chunks
	for {
		n, err := reader.Read(chunk)
		if n > 0 {
			buffer.Write(chunk[:n])
			data := buffer.Bytes()

			offset := 0
			dataLen := len(data)

			// Process all JSON objects in current buffer
			for offset < dataLen {
				// Find next JSON object or array start
				if offset < dataLen {
					nextJSON := bytes.IndexAny(data[offset:], "{[")
					if nextJSON == -1 {
						offset = dataLen // No more JSON objects in buffer
						break
					}
					offset += nextJSON
				}

				if offset >= dataLen {
					break
				}

				// Process either object or array based on first character
				switch data[offset] {
				case '{':
					// Get a map from pool and clear it for reuse
					obj := mapPool.Get().(map[string]interface{})
					for k := range obj {
						delete(obj, k)
					}

					// Try to decode a single object
					if err := json.NewDecoder(bytes.NewReader(data[offset:])).Decode(&obj); err != nil {
						mapPool.Put(obj) // Return failed object to pool
						offset++         // Skip this character and try next position
						continue
					}

					results = append(results, obj)
					// Calculate exact size of processed object to advance offset
					if encoded, err := json.Marshal(obj); err == nil {
						offset += len(encoded)
					} else {
						offset++ // Fallback on error
					}
				case '[':
					// Handle JSON arrays
					var arrayObj []map[string]interface{}
					if err := json.NewDecoder(bytes.NewReader(data[offset:])).Decode(&arrayObj); err != nil {
						// Clean up any partially decoded array objects
						for _, m := range arrayObj {
							mapPool.Put(m)
						}
						offset++
						continue
					}

					results = append(results, arrayObj...)
					// Calculate exact size of processed array
					if encoded, err := json.Marshal(arrayObj); err == nil {
						offset += len(encoded)
					} else {
						offset++
					}
				}
			}

			// Manage buffer content: keep unprocessed data for next iteration
			if offset < dataLen {
				buffer.Next(offset) // Efficiently remove processed data without allocation
			} else {
				buffer.Reset() // Clear buffer if all data was processed
			}
		}

		if err == io.EOF {
			break // End of input
		}
		if err != nil {
			return nil, fmt.Errorf("error reading input: %w", err)
		}
	}

	// Ensure we found at least one valid JSON object
	if len(results) == 0 {
		return nil, fmt.Errorf("no valid JSON objects found in input")
	}

	return results, nil
}
